import{a as e}from"./chunk-LFCGMLSM.js";import"./chunk-IFGU66OU.js";var t={meta:e,sections:[{id:"overview",title:"Overview",blocks:[{type:"markdown",value:"A **Canary Release** ships a new version to a **small percentage** of traffic (or users) first. You watch error rate, latency, and business metrics; if healthy, you ramp up. If not, you roll back with limited blast radius."},{type:"callout",variant:"info",title:"Name origin",body:"Like a canary in a coal mine \u2014 a small exposed group detects danger before the whole flock (fleet) is at risk."}]},{id:"concept",title:"Concept and analogy",blocks:[{type:"callout",variant:"tip",title:"Real-world analogy",body:"A restaurant tries a **new menu on 5 tables** before printing it for the whole dining room. Feedback is real, cost of a bad dish is contained."},{type:"mermaid",caption:"Traffic split between stable and canary.",definition:`flowchart LR
  U[Users] --> R[Router / Mesh]
  R -->|95%| S[Stable v1]
  R -->|5%| C[Canary v2]`}]},{id:"where-used",title:"Where it is used",blocks:[{type:"table",headers:["Domain","Example"],rows:[["Kubernetes","Flagger, Argo Rollouts, Istio/Linkerd weight splits"],["Cloud LBs","Weighted target groups / traffic shifting"],["Mobile","Staged rollouts in Play Store / App Store"],["Frontends","Canary JS bundles via CDN percentage"],["Data jobs","Canary consumers on one partition first"]]}]},{id:"implementation",title:"Implementation",blocks:[{type:"markdown",value:"Progressive delivery steps with metric gates:"},{type:"timeline",items:[{title:"Deploy canary",description:"Run v2 on a few pods; send 1\u20135% traffic.",meta:"1%"},{title:"Compare metrics",description:"Error rate, p99 latency, saturation vs stable baseline.",meta:"Gate"},{title:"Ramp",description:"Increase to 25% \u2192 50% \u2192 100% if gates pass.",meta:"Promote"},{title:"Abort",description:"On regression, shift weight back to stable immediately.",meta:"Rollback"}]},{type:"code",language:"yaml",filename:"canary-weights.example.yaml",code:`# Conceptual Istio / mesh style split
# stable: 95%, canary: 5%
http:
  - route:
      - destination:
          host: checkout
          subset: stable
        weight: 95
      - destination:
          host: checkout
          subset: canary
        weight: 5`},{type:"prosCons",title:"Trade-offs",pros:["Limits blast radius of bad releases.","Uses real production traffic (better than staging alone).","Pairs well with automated analysis and rollback."],cons:["Needs solid metrics and routing infrastructure.","Sticky sessions / rare bugs may miss the canary cohort.","More complex than a simple rolling update."]}]},{id:"interview-questions",title:"Interview Questions",blocks:[{type:"interviewQa",items:[{question:"What is a canary release?",answer:"Deploying a new version to a **small slice** of traffic, validating metrics, then gradually promoting \u2014 or rolling back if unhealthy."},{question:"Canary vs blue-green?",answer:"Canary **ramps traffic** gradually. Blue-green usually **flips 100%** after validation on a parallel environment. Canary minimizes blast radius; blue-green optimizes for a clean cutover."},{question:"Canary vs feature flag?",answer:"Canary is often a **version/traffic** strategy. Feature flags can canary **by user/segment inside one binary**. Many teams use both."},{question:"What metrics gate a promote decision?",answer:"HTTP 5xx rate, latency percentiles, saturation (CPU/RPS), and **business KPIs** (checkout conversion). Compare canary vs stable, not absolute thresholds alone."},{question:"How do you pick the canary population?",answer:"Random percentage, internal employees first, or low-risk regions. Avoid only \u201Cfriendly\u201D users if you need representative load."}]}]},{id:"summary",title:"Summary",blocks:[{type:"callout",variant:"summary",title:"Key takeaways",body:`1. Ship to a **small %**, measure, then ramp.
2. Automate **promote/abort** on metrics.
3. Real uses: **service mesh, Argo, mobile staged rollout**.
4. Contrast with blue-green and feature flags.`}]}]},i=t;export{i as default};
